依次迭代计算。用变量 r 记录当前结果，初始 r = 1，从 i = 2 循环到 n，每次 r = (r + i) * abs(r - i)。注意 n ≤ 20，结果在 int 范围内。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, r = 1;
    cin >> n;
    for (int i = 2; i <= n; i++) {
        r = (r + i) * abs(r - i);
    }
    cout << r << endl;
    return 0;
}
```

用两个变量：work_days 记录连续工作天数，total 累计总和。遍历每一天：如果 work_days == 7 则休整（work_days 归零，当天不采）；否则当天采 (10 + work_days * 3) 朵，work_days++，累加进 total。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, total = 0, work_days = 0;
    cin >> n;
    for (int day = 1; day <= n; day++) {
        if (work_days == 7) {
            work_days = 0;          // 休整
        } else {
            total += 10 + work_days * 3;
            work_days++;
        }
    }
    cout << total << endl;
    return 0;
}
```

先排序，然后遍历。用 cnt 记录当前连续段长度，当前数比前一个数大 1 则 cnt++，否则更新答案并重置 cnt = 1。注意去重——如果当前数等于前一个数，跳过。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, a[1005];
    cin >> n;
    for (int i = 0; i < n; i++) cin >> a[i];
    sort(a, a + n);
    int ans = 1, cnt = 1;
    for (int i = 1; i < n; i++) {
        if (a[i] == a[i - 1]) continue;       // 重复数字跳过
        if (a[i] == a[i - 1] + 1) cnt++;       // 连续
        else cnt = 1;                           // 断开了
        ans = max(ans, cnt);
    }
    cout << ans << endl;
    return 0;
}
```

排序后单遍扫描统计频次。用 cnt 记录当前数的出现次数，当前数与前一个不同时输出。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, a[1005];
    cin >> n;
    for (int i = 0; i < n; i++) cin >> a[i];
    sort(a, a + n);
    int cnt = 1;
    for (int i = 1; i < n; i++) {
        if (a[i] == a[i - 1]) cnt++;
        else {
            cout << a[i - 1] << " " << cnt << endl;
            cnt = 1;
        }
    }
    cout << a[n - 1] << " " << cnt << endl;
    return 0;
}
```

从高到低排序后，按比例切分人数。注意处理人数不足的情况。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, a[1005];
    cin >> n;
    for (int i = 0; i < n; i++) cin >> a[i];
    sort(a, a + n, greater<int>());  // 从高到低
    int cnt1 = n * 20 / 100;  // 一等奖人数
    int cnt2 = n * 30 / 100;  // 二等奖人数
    int score1 = (cnt1 == 0) ? -1 : a[cnt1 - 1];
    int score2 = (cnt2 == 0 || cnt1 + cnt2 > n) ? -1 : a[cnt1 + cnt2 - 1];
    cout << score1 << " " << score2 << endl;
    return 0;
}
```
